        if (!dataForSubmission.id) dataForSubmission.id = `c${Date.now()}`;

        const qrBase = dataForSubmission['Заказ - QR'] || '';
        dataForSubmission['Заказ - QR'] = description ? `${qrBase} >> ${description}` : qrBase;

